- Copy and paste the code example into the
  `compound-constant-query.go` file.

  The code example performs the following tasks:

  - Imports `mongodb` packages and dependencies.

  - Establishes a connection to your cluster.

  - Uses the following compound clauses to query the collection:

    - `filter` clause with the [range](range-ref) operator to
      search for movies between the years `2013` to `2015`.

    - `should` clause with the [text](text-ref) operator to query
      for the term `snow` in the `title` field and alter the
      `score` with the `constant` option. The `constant` option
      replaces all score results for the search term with `5`.

  - Specifies the [highlights](highlight-ref) option to return snippets of text
    from the `title` field that match the query. The snippets contain
    matching text specified with `type: 'hit'`, and adjacent text
    specified with `type: 'text'`.

  - Uses the following pipeline stages:

    - [$limit](manual/reference/operator/aggregation/limit) stage to
      limit the output to 10 results

    - [$project](manual/reference/operator/aggregation/project) stage
      to:

      - Exclude all fields except `title` and `year`

      - Add two fields named `score` and `highlights`

  - Iterates over the cursor to print the documents that match the
    query.

  ```go
  package main

  import (
  	"context"
  	"fmt"
  	"time"

  	"go.mongodb.org/mongo-driver/v2/bson"
  	"go.mongodb.org/mongo-driver/v2/mongo"
  	"go.mongodb.org/mongo-driver/v2/mongo/options"
  )

  func main() {
  	// connect to the Atlas cluster and set a maximum operation time
  	opts := options.Client().
  		SetTimeout(5 * time.Second).
  		ApplyURI("<connection-string>")

  	client, err := mongo.Connect(opts)
  	if err != nil {
  		panic(err)
  	}
  	defer client.Disconnect(context.TODO())

  	// set namespace
  	collection := client.Database("sample_mflix").Collection("movies")

  	// define pipeline stages
  	searchStage := bson.D{{"$search", bson.M{
  		"index": "default",
  		"compound": bson.M{
  			"filter": bson.M{
  				"range": bson.M{
  					"path": "year", "gte": 2013, "lte": 2015,
  				},
  			},
  			"should": bson.D{
  				{"text", bson.M{
  					"path": "title", "query": "snow", "score": bson.M{
  						"constant": bson.D{{"value", 5}},
  					}}}},
  		},
  		"highlight": bson.D{{"path", "title"}},
  	}}}
  	limitStage := bson.D{{"$limit", 10}}
  	projectStage := bson.D{{"$project", bson.D{{"title", 1}, {"year", 1}, {"_id", 0}, {"score", bson.D{{"$meta", "searchScore"}}}, {"highlights", bson.D{{"$meta", "searchHighlights"}}}}}}

  	// run pipeline
  	cursor, err := collection.Aggregate(context.TODO(), mongo.Pipeline{searchStage, limitStage, projectStage})
  	if err != nil {
  		panic(err)
  	}

  	// print results
  	var results []bson.D
  	if err = cursor.All(context.TODO(), &results); err != nil {
  		panic(err)
  	}
  	for _, result := range results {
  		fmt.Println(result)
  	}
  }

  ```

